const AdminService = require('../services/adminService');

class AdminController {
  static async getLessons(req, res) {
    try {
      const result = await AdminService.getLessonsPaginated(req.query);
      res.json(result);
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }

  static async createLesson(req, res) {
    try {
      const lesson = await AdminService.createLesson(req.body);
      res.status(201).json(lesson);
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }

  static async updateLesson(req, res) {
    try {
      const updatedLesson = await AdminService.updateLesson(req.params.id, req.body);
      res.json(updatedLesson);
    } catch (err) {
      if (err.message === 'NOT_FOUND') {
        return res.status(404).json({ error: 'Урок не найден' });
      }
      res.status(500).json({ error: err.message });
    }
  }

  static async deleteLesson(req, res) {
    try {
      await AdminService.deleteLesson(req.params.id);
      res.json({ message: 'Урок успешно удален' });
    } catch (err) {
      if (err.message === 'NOT_FOUND') {
        return res.status(404).json({ error: 'Урок не найден' });
      }
      res.status(500).json({ error: err.message });
    }
  }
}

module.exports = AdminController;

const AdminService = require('../services/adminService');
const AuditLogService = require('../services/auditLogService');
const LessonModel = require('../models/lessonModel');

class AdminController {
  static async getLessons(req, res) {
    try {
      const result = await AdminService.getLessonsPaginated(req.query);
      res.json(result);
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }

  static async createLesson(req, res) {
    try {
      const lesson = await AdminService.createLesson(req.body);
      await AuditLogService.log({
        userId: req.userId,
        action: 'CREATE_LESSON',
        entity: 'lesson',
        entityId: lesson.id,
        before: null,
        after: lesson
      });
      res.status(201).json(lesson);
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  }

  static async updateLesson(req, res) {
    try {
      const before = await LessonModel.findById(req.params.id);
      const updatedLesson = await AdminService.updateLesson(req.params.id, req.body);
      await AuditLogService.log({
        userId: req.userId,
        action: 'UPDATE_LESSON',
        entity: 'lesson',
        entityId: req.params.id,
        before,
        after: updatedLesson
      });
      res.json(updatedLesson);
    } catch (err) {
      if (err.message === 'NOT_FOUND') {
        return res.status(404).json({ error: 'Урок не найден' });
      }
      res.status(500).json({ error: err.message });
    }
  }

  static async deleteLesson(req, res) {
    try {
      const before = await LessonModel.findById(req.params.id);
      await AdminService.deleteLesson(req.params.id);
      await AuditLogService.log({
        userId: req.userId,
        action: 'DELETE_LESSON',
        entity: 'lesson',
        entityId: req.params.id,
        before,
        after: null
      });
      res.json({ message: 'Урок успешно удален' });
    } catch (err) {
      if (err.message === 'NOT_FOUND') {
        return res.status(404).json({ error: 'Урок не найден' });
      }
      res.status(500).json({ error: err.message });
    }
  }
}

module.exports = AdminController;

const prisma = require('../prismaClient');

class AuditLogModel {
  static async create({ userId, action, entity, entityId, before, after }) {
    return await prisma.audit_log.create({
      data: {
        user_id: userId,
        action,
        entity,
        entity_id: entityId,
        before,
        after
      }
    });
  }
}

module.exports = AuditLogModel;

generator client { provider = "prisma-client-js" }
datasource db { provider = "postgresql" url = env("DATABASE_URL") }
model units { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid title String @db.VarChar(255) description String? order_index Int @unique created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) lessons lessons[] }
model lessons { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid unit_id String? @db.Uuid // Ссылка на юнит title String @db.VarChar(255) description String? order_index Int @unique xp_reward Int? @default(50) is_published Boolean? @default(false) created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6)
units units? @relation(fields: [unit_id], references: [id], onDelete: Cascade) exercises exercises[] progress progress[] }
model exercises { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid lesson_id String @db.Uuid type exercise_type question_data Json correct_answer String xp_value Int? @default(10) order_index Int created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) exercise_attempts exercise_attempts[] lessons lessons @relation(fields: [lesson_id], references: [id], onDelete: Cascade, onUpdate: NoAction) }
model users { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid email String? @unique @db.VarChar(255) password_hash String? @db.VarChar(255) role user_role parent_id String? @db.Uuid name String @db.VarChar(255) pin String? @db.VarChar(255) avatar_url String? created_at DateTime @default(now()) @db.Timestamptz(6) updated_at DateTime @default(now()) @db.Timestamptz(6)
exercise_attempts exercise_attempts[] notifications notifications[] progress progress[] streaks streaks? user_badges user_badges[]
parent users? @relation("ParentToChild", fields: [parent_id], references: [id], onDelete: Cascade) children users[] @relation("ParentToChild")
@@index([email], map: "idx_users_email") @@index([parent_id], map: "idx_users_parent_id") @@index([role], map: "idx_users_role") }
model exercise_attempts { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid child_id String @db.Uuid exercise_id String @db.Uuid correct Boolean xp_earned Int? @default(0) attempted_at DateTime? @default(now()) @db.Timestamptz(6) created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) users users @relation(fields: [child_id], references: [id], onDelete: Cascade, onUpdate: NoAction) exercises exercises @relation(fields: [exercise_id], references: [id], onDelete: Cascade, onUpdate: NoAction)
@@index([child_id], map: "idx_attempts_child") }
model progress { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid child_id String @db.Uuid lesson_id String @db.Uuid completed Boolean? @default(false) score Int? @default(0) started_at DateTime? @default(now()) @db.Timestamptz(6) completed_at DateTime? @db.Timestamptz(6) created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) users users @relation(fields: [child_id], references: [id], onDelete: Cascade, onUpdate: NoAction) lessons lessons @relation(fields: [lesson_id], references: [id], onDelete: Cascade, onUpdate: NoAction)
@@unique([child_id, lesson_id]) @@index([child_id, lesson_id], map: "idx_progress_child_lesson") }
model streaks { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid child_id String @unique @db.Uuid current_streak Int? @default(0) longest_streak Int? @default(0) last_activity_date DateTime? @db.Date created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) users users @relation(fields: [child_id], references: [id], onDelete: Cascade, onUpdate: NoAction)
@@index([child_id], map: "idx_streaks_child") }
model user_badges { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid child_id String @db.Uuid badge_id String @db.Uuid awarded_at DateTime? @default(now()) @db.Timestamptz(6) created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) badges badges @relation(fields: [badge_id], references: [id], onDelete: Cascade, onUpdate: NoAction) users users @relation(fields: [child_id], references: [id], onDelete: Cascade, onUpdate: NoAction)
@@unique([child_id, badge_id]) @@index([child_id], map: "idx_user_badges_child") }
model badges { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid name String @unique @db.VarChar(255) description String? criteria_type badge_criteria_type criteria_value Int icon_url String? created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) user_badges user_badges[] }
model notifications { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid user_id String @db.Uuid type notification_type message String read Boolean? @default(false) created_at DateTime? @default(now()) @db.Timestamptz(6) updated_at DateTime? @default(now()) @db.Timestamptz(6) users users @relation(fields: [user_id], references: [id], onDelete: Cascade, onUpdate: NoAction)
@@index([user_id], map: "idx_notifications_user") }
model audit_log { id String @id @default(dbgenerated("gen_random_uuid()")) @db.Uuid user_id String? @db.Uuid action String // e.g. 'CREATE_LESSON', 'UPDATE_BADGE' entity String // e.g. 'lesson', 'badge' entity_id String? @db.Uuid before Json? after Json? created_at DateTime @default(now()) @db.Timestamptz(6) }
enum badge_criteria_type { lessons_completed total_xp streak_days }
enum exercise_type { phonics handwriting sight_words vocabulary }
enum notification_type { badge streak lesson_complete }
enum user_role { parent child admin }

